def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -1.0, dtype=float)
    epsilon = 1e-9
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        base_priority = 0.0
        if usage_ratio > 1.5:
            base_priority = 2000 * usage_ratio
        elif usage_ratio > 1.0:
            base_priority = 1000 * usage_ratio
        elif usage_ratio == 1.0:
            base_priority = 20
        else:
            diff = 1 - usage_ratio
            log_val = np.log(diff + epsilon)
            if log_val < -2:
                base_priority = -log_val * 10
            elif log_val < -1:
                base_priority = -log_val * 7
            else:
                base_priority = -log_val * 2
        if capacity < 0.05:
            base_priority += 70
            if usage_ratio < 0.5:
                base_priority += (0.5 - usage_ratio) * 100
        elif capacity < 0.2:
            base_priority += 30
            base_priority += (0.2 - capacity) * 50
        elif capacity < 1:
            base_priority += 10
            if item > capacity / 2:
                base_priority += 20
            else:
                base_priority -= 5
        if 0.8 <= usage_ratio <= 1:
            for j in range(len(bins)):
                if j != i:
                    ratio_diff = abs(usage_ratio - item / bins[j])
                    if ratio_diff < 0.1:
                        base_priority += 15
        if capacity > 5:
            base_priority -= capacity * 0.1
        priorities[i] = base_priority
    return priorities
